public void testAppendFixedWidthPadLeftLongerString() {
    StrBuilder sb = new StrBuilder();
    sb.appendFixedWidthPadLeft("HelloWorld", 5, '*');
    assertEquals("World", sb.toString());
}

public void testAppendFixedWidthPadRightLongerString() {
    StrBuilder sb = new StrBuilder();
    sb.appendFixedWidthPadRight("HelloWorld", 5, '*');
    assertEquals("Hello", sb.toString());
}

public void testAppendFixedWidthPadLeftShorterString() {
    StrBuilder sb = new StrBuilder();
    sb.appendFixedWidthPadLeft("Hi", 5, '*');
    assertEquals("***Hi", sb.toString());
}

public void testAppendFixedWidthPadRightShorterString() {
    StrBuilder sb = new StrBuilder();
    sb.appendFixedWidthPadRight("Hi", 5, '*');
    assertEquals("Hi***", sb.toString());
}

public void testAppendFixedWidthPadLeftZeroWidth() {
    StrBuilder sb = new StrBuilder();
    sb.append("Test");
    sb.appendFixedWidthPadLeft("Hello", 0, '*');
    assertEquals("Test", sb.toString());
}
